import type { ComponentProps, ComponentPropsWithoutRef } from 'react';
import clsx from 'clsx';
import styles from './Alert.module.css';

type AlertVariant = 'default' | 'info' | 'success' | 'warning' | 'destructive';
type AlertTitleElement = 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';

function Alert({
  className,
  role,
  variant = 'default',
  ...props
}: ComponentProps<'div'> & {
  variant?: AlertVariant;
}) {
  return (
    <div
      role={role ?? (variant === 'destructive' ? 'alert' : 'status')}
      data-slot="alert-root"
      data-variant={variant}
      className={clsx(styles.root, className)}
      {...props}
    />
  );
}

function AlertIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="alert-icon"
      aria-hidden="true"
      className={clsx(styles.icon, className)}
      {...props}
    />
  );
}

function AlertContent({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="alert-content" className={clsx(styles.content, className)} {...props} />;
}

function AlertTitle({
  as: Root = 'h3',
  className,
  ...props
}: ComponentPropsWithoutRef<'h3'> & {
  as?: AlertTitleElement;
}) {
  return <Root data-slot="alert-title" className={clsx(styles.title, className)} {...props} />;
}

function AlertDescription({ className, ...props }: ComponentProps<'div'>) {
  return (
    <div data-slot="alert-description" className={clsx(styles.description, className)} {...props} />
  );
}

export { Alert, AlertIcon, AlertContent, AlertTitle, AlertDescription };
export type { AlertVariant, AlertTitleElement };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: auto minmax(0, 1fr);
    align-items: start;
    width: 100%;
    min-width: 0;
    gap: var(--alert-gap, var(--spacing-3));
    border: var(--alert-border-width, var(--border-width-sm)) solid
      var(--alert-border-color, var(--alert-border-color-default, var(--color-border)));
    border-radius: var(--alert-radius, var(--radius-lg));
    padding: var(--alert-padding, var(--spacing-4));
    background-color: var(--alert-bg, var(--alert-bg-default, var(--color-card)));
    color: var(--alert-color, var(--alert-color-default, var(--color-card-foreground)));
    box-shadow: var(--alert-shadow, none);

    &[data-variant='default'] {
      --alert-bg-default: var(--color-card);
      --alert-border-color-default: var(--color-border);
      --alert-color-default: var(--color-card-foreground);
      --alert-icon-color-default: var(--color-muted-foreground);
    }

    &[data-variant='info'] {
      --alert-bg-default: color-mix(in oklab, var(--color-primary) 4%, var(--color-background));
      --alert-border-color-default: color-mix(in oklab, var(--color-primary) 32%, transparent);
      --alert-color-default: var(--color-foreground);
      --alert-icon-color-default: var(--color-primary);
    }

    &[data-variant='success'] {
      --alert-bg-default: color-mix(
        in oklab,
        var(--alert-success-color, #16a34a) 10%,
        var(--color-background)
      );
      --alert-border-color-default: color-mix(
        in oklab,
        var(--alert-success-color, #16a34a) 34%,
        transparent
      );
      --alert-color-default: var(--color-foreground);
      --alert-icon-color-default: var(--alert-success-color, #16a34a);
    }

    &[data-variant='warning'] {
      --alert-bg-default: color-mix(
        in oklab,
        var(--alert-warning-color, #ca8a04) 13%,
        var(--color-background)
      );
      --alert-border-color-default: color-mix(
        in oklab,
        var(--alert-warning-color, #ca8a04) 38%,
        transparent
      );
      --alert-color-default: var(--color-foreground);
      --alert-icon-color-default: var(--alert-warning-color, #ca8a04);
    }

    &[data-variant='destructive'] {
      --alert-bg-default: color-mix(in oklab, var(--color-destructive) 9%, var(--color-background));
      --alert-border-color-default: color-mix(in oklab, var(--color-destructive) 35%, transparent);
      --alert-color-default: var(--color-foreground);
      --alert-icon-color-default: var(--color-destructive);
    }
  }

  .icon {
    display: inline-flex;
    width: var(--alert-icon-size, 1rem);
    height: var(--alert-icon-size, 1rem);
    align-items: center;
    justify-content: center;
    color: var(--alert-icon-color, var(--alert-icon-color-default, currentColor));
    margin-block-start: var(--alert-icon-offset, 0.125rem);

    & :where(svg),
    &:where(svg) {
      width: var(--alert-icon-size, 1rem);
      height: var(--alert-icon-size, 1rem);
      flex-shrink: 0;
      pointer-events: none;
    }
  }

  .content {
    display: grid;
    min-width: 0;
    gap: var(--alert-content-gap, var(--spacing-1));
  }

  .title {
    margin: 0;
    min-width: 0;
    color: var(--alert-title-color, var(--alert-color, var(--alert-color-default)));
    font-size: var(--alert-title-font-size, var(--text-sm));
    font-weight: var(--alert-title-font-weight, var(--weight-semibold));
    line-height: var(--alert-title-line-height, var(--line-height-text-sm));
    overflow-wrap: anywhere;
  }

  .description {
    min-width: 0;
    color: var(--alert-description-color, var(--color-muted-foreground));
    font-size: var(--alert-description-font-size, var(--text-sm));
    line-height: var(--alert-description-line-height, var(--line-height-text-sm));
    overflow-wrap: anywhere;

    & > :first-child {
      margin-top: 0;
    }

    & > :last-child {
      margin-bottom: 0;
    }
  }

  .root:not(:has([data-slot='alert-icon'])) .content {
    grid-column: 1 / -1;
  }
}
